package dev.nimbuspowered.nimbus.plugin;

import com.google.gson.Gson;
import com.google.gson.annotations.SerializedName;

import java.io.IOException;
import java.nio.file.Files;
import java.nio.file.Path;

/**
 * Configuration for the Nimbus Bridge (API connection).
 * Auto-generated by Nimbus Core during deployment.
 */
public class BridgeConfig {

    @SerializedName("api_url")
    private String apiUrl = "http://127.0.0.1:8080";

    @SerializedName("token")
    private String token = "";

    public String getApiUrl() {
        return apiUrl;
    }

    public String getToken() {
        return token;
    }

    public static BridgeConfig load(Path dataDirectory) throws IOException {
        // 1. Try JVM system properties (injected by Nimbus Core at startup)
        String sysUrl = System.getProperty("nimbus.api.url");
        if (sysUrl != null && !sysUrl.isEmpty()) {
            BridgeConfig config = new BridgeConfig();
            config.apiUrl = sysUrl;
            // Token: prefer env var (hidden from ps), fall back to system property for backwards compat
            String envToken = System.getenv("NIMBUS_API_TOKEN");
            config.token = (envToken != null && !envToken.isEmpty())
                    ? envToken
                    : System.getProperty("nimbus.api.token", "");
            return config;
        }

        // 2. Fall back to bridge.json file
        Path configFile = dataDirectory.resolve("bridge.json");
        if (!Files.exists(configFile)) {
            return null;
        }
        String json = Files.readString(configFile);
        return new Gson().fromJson(json, BridgeConfig.class);
    }
}
